function ttlMs(c) {
  var u = c.ttlUnit || 'hours';
  var v;
  if (c.ttlValue != null && c.ttlValue !== '') v = Number(c.ttlValue);
  else if (c.ttlHours != null && c.ttlHours !== '') { v = Number(c.ttlHours); u = 'hours'; }
  else return 0;
  if (!(v > 0) || v !== v) return 0;
  if (u === 'minutes') return v * 60 * 1000;
  if (u === 'days') return v * 24 * 3600000;
  return v * 3600000;
}
