  var cd = new Date(cutoffMs);
  var y = cd.getUTCFullYear();
  var mo = ('0' + (cd.getUTCMonth() + 1)).slice(-2);
  var da = ('0' + cd.getUTCDate()).slice(-2);
  parts.push(cfg.mapping.timeField + " >= DATE '" + y + '-' + mo + '-' + da + "'");
