var staleMs = tm > 0 ? tm : 3600000;
var stale = new Date(now.getTime() + staleMs);
var isPoly = cfg.source.geometryType !== 'esriGeometryPoint';
var cotType = isPoly ? 'u-d-f' : 'a-u-G';

var results = [];
for (var i = 0; i < features.length; i++) {
  var f = features[i];
  var a = f.attributes || {};
